//! PKCS#12 KAT (`storageUtest/c/utest_pkcs12_dstu.c`).

use uacryptex_core::storage::pkcs12::{
    pkcs12_create, pkcs12_decode, pkcs12_encode, pkcs12_enum_keys, pkcs12_generate_key,
    pkcs12_get_dh_adapter, pkcs12_get_sign_adapter, pkcs12_get_storage_name,
    pkcs12_get_verify_adapter, pkcs12_select_key, pkcs12_set_certificates, pkcs12_store_key,
    Pkcs12AuthType, Pkcs12MacType,
};
use uacryptex_core::Error;

const IIT_PFX: &[u8] = include_bytes!("../../../testdata/storage/pkcs12_by_iit.pfx");
const PKCS8_CRT: &[u8] = include_bytes!("../../../testdata/storage/pkcs8.crt");

const MAC_VERIFY_ERROR_PFX: &str = "";

const UNSUP_CINFO_PFX: &str = "";

fn hex(s: &str) -> Vec<u8> {
    hex::decode(s).expect("valid hex")
}

#[test]
fn pkcs12_decode_iit_storage() {
    let path = "testdata/storage/pkcs12_by_iit.pfx";
    let mut store = pkcs12_decode(Some(path), IIT_PFX, "123456").expect("decode IIT pfx");
    assert_eq!(pkcs12_get_storage_name(&store), Some(path));

    let keys = pkcs12_enum_keys(&mut store).expect("enum keys");
    assert_eq!(keys.len(), 2);
    assert_eq!(keys[0].alias, "key1");
    assert_eq!(keys[1].alias, "key2");
    assert_eq!(keys[0].auth, Pkcs12AuthType::StoragePass);
    assert_eq!(keys[1].auth, Pkcs12AuthType::StoragePass);
}

#[test]
fn pkcs12_decode_mac_verify_error() {
    let err = pkcs12_decode(None, &hex(MAC_VERIFY_ERROR_PFX), "123456").unwrap_err();
    assert_eq!(err, Error::VerifyFailed);
}

#[test]
fn pkcs12_decode_unsupported_cinfo_type() {
    let err = pkcs12_decode(None, &hex(UNSUP_CINFO_PFX), "123456").unwrap_err();
    assert!(matches!(err, Error::Unsupported(_)));
}

#[test]
fn pkcs12_select_key_and_sign_verify() {
    let mut store = pkcs12_decode(None, IIT_PFX, "123456").expect("decode IIT pfx");
    pkcs12_set_certificates(&mut store, &[PKCS8_CRT]).expect("set certificates");

    assert!(matches!(
        pkcs12_get_sign_adapter(&store),
        Err(Error::StorageKeyNotSelected)
    ));
    assert!(matches!(
        pkcs12_get_verify_adapter(&store),
        Err(Error::StorageKeyNotSelected)
    ));

    pkcs12_select_key(&mut store, Some("key1"), Some("123456")).expect("select key1");

    let sa = pkcs12_get_sign_adapter(&store).expect("sign adapter");
    let va = pkcs12_get_verify_adapter(&store).expect("verify adapter");

    let mut data = vec![0u8; 99];
    data.fill(0x49);
    let signature = sa.sign_data(&data).expect("sign");
    va.verify_data(&data, &signature).expect("verify");
}

#[test]
fn pkcs12_select_first_key_without_alias() {
    let mut store = pkcs12_decode(None, IIT_PFX, "123456").expect("decode");
    pkcs12_select_key(&mut store, None, None).expect("select first key");
    pkcs12_get_verify_adapter(&store).expect("verify adapter");
}

#[test]
fn pkcs12_get_dh_adapter_after_select() {
    let mut store = pkcs12_decode(None, IIT_PFX, "123456").expect("decode");
    pkcs12_select_key(&mut store, None, None).expect("select key");
    pkcs12_get_dh_adapter(&store).expect("dh adapter");
}

#[test]
fn pkcs12_create_generate_store_encode_decode() {
    let mut store = pkcs12_create(Pkcs12MacType::Gost34311, "123456", 1024).expect("create");
    pkcs12_generate_key(&mut store, None).expect("generate dstu key");
    pkcs12_store_key(&mut store, Some("key1"), Some("123456"), 1024).expect("store key");
    pkcs12_generate_key(&mut store, None).expect("generate second key");
    pkcs12_store_key(&mut store, Some("key2"), Some("123456"), 1024).expect("store key2");

    let encoded = pkcs12_encode(&store).expect("encode");
    let mut decoded = pkcs12_decode(None, &encoded, "123456").expect("decode");
    let keys = pkcs12_enum_keys(&mut decoded).expect("enum keys");
    assert_eq!(keys.len(), 2);
    assert_eq!(keys[0].alias, "key1");
    assert_eq!(keys[1].alias, "key2");
}
